"""
Parameterized generator for GH1151_pymc_7856.

Source PR:    https://github.com/pymc-devs/pymc/pull/7856
Source Issue: N/A

Seed varies: renames 'chain' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1151_pymc_7856'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1151_pymc_7856'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('chain', 'chain' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1151_pymc_7856',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'pymc-devs/pymc',
                "pr_number": 7856,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/pymc-devs/pymc/pull/7856",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'pymc/backends/arviz.py': '#   Copyright 2024 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\n"""PyMC-ArviZ conversion code."""\n\nimport logging\nimport warnings\n\nfrom collections.abc import Iterable, Mapping, Sequence\nfrom typing import (\n    TYPE_CHECKING,\n    Any,\n    Optional,\n    Union,\n    cast,\n)\n\nimport numpy as np\nimport xarray\n\nfrom arviz import InferenceData, concat, rcParams\nfrom arviz.data.base import CoordSpec, DimSpec, dict_to_dataset, requires\nfrom pytensor.graph import ancestors\nfrom pytensor.tensor.sharedvar import SharedVariable\nfrom rich.progress import Console\nfrom rich.theme import Theme\nfrom xarray import Dataset\n\nimport pymc\n\nfrom pymc.model import Model, modelcontext\nfrom pymc.progress_bar import CustomProgress, default_progress_theme\nfrom pymc.pytensorf import PointFunc, extract_obs_data\nfrom pymc.util import get_default_varnames\n\nif TYPE_CHECKING:\n    from pymc.backends.base import MultiTrace\n\n___all__ = [""]\n\n_log = logging.getLogger(__name__)\n\n# random variable object ...\nVar = Any\n\n\ndef find_observations(model: "Model") -> dict[str, Var]:\n    """If there are observations available, return them as a dictionary."""\n    observations = {}\n    for obs in model.observed_RVs:\n        aux_obs = model.rvs_to_values.get(obs, None)\n        if aux_obs is not None:\n            try:\n                obs_data = extract_obs_data(aux_obs)\n                observations[obs.name] = obs_data\n            except TypeError:\n                warnings.warn(f"Could not extract data from symbolic observation {obs}")\n        else:\n            warnings.warn(f"No data for observation {obs}")\n\n    return observations\n\n\ndef find_constants(model: "Model") -> dict[str, Var]:\n    """If there are constants available, return them as a dictionary."""\n    model_vars = model.basic_RVs + model.deterministics + model.potentials\n    value_vars = set(model.rvs_to_values.values())\n\n    constant_data = {}\n    for var in model.data_vars:\n        if var in value_vars:\n            # An observed value variable could also be part of the generative graph\n            if var not in ancestors(model_vars):\n                continue\n\n        if isinstance(var, SharedVariable):\n            var_value = var.get_value()\n        else:\n            var_value = var.data\n        constant_data[var.name] = var_value\n\n    return constant_data\n\n\ndef coords_and_dims_for_inferencedata(model: Model) -> tuple[dict[str, Any], dict[str, Any]]:\n    """Parse PyMC model coords and dims format to one accepted by InferenceData."""\n    coords = {\n        cname: np.array(cvals) if isinstance(cvals, tuple) else cvals\n        for cname, cvals in model.coords.items()\n        if cvals is not None\n    }\n    dims = {dname: list(dvals) for dname, dvals in model.named_vars_to_dims.items()}\n\n    return coords, dims\n\n\nclass _DefaultTrace:\n    """\n    Utility for collecting samples into a dictionary.\n\n    Name comes from its similarity to ``defaultdict``:\n    entries are lazily created.\n\n    Parameters\n    ----------\n    samples : int\n        The number of samples that will be collected, per variable,\n        into the trace.\n\n    Attributes\n    ----------\n    trace_dict : Dict[str, np.ndarray]\n        A dictionary constituting a trace.  Should be extracted\n        after a procedure has filled the `_DefaultTrace` using the\n        `insert()` method\n    """\n\n    def __init__(self, samples: int):\n        self._len: int = samples\n        self.trace_dict: dict[str, np.ndarray] = {}\n\n    def insert(self, k: str, v, idx: int):\n        """\n        Insert `v` as the value of the `idx`th sample for the variable `k`.\n\n        Parameters\n        ----------\n        k: str\n            Name of the variable.\n        v: anything that can go into a numpy array (including a numpy array)\n            The value of the `idx`th sample from variable `k`\n        ids: int\n            The index of the sample we are inserting into the trace.\n        """\n        value_shape = np.shape(v)\n\n        # initialize if necessary\n        if k not in self.trace_dict:\n            array_shape = (self._len, *value_shape)\n            self.trace_dict[k] = np.empty(array_shape, dtype=np.array(v).dtype)\n\n        # do the actual insertion\n        if value_shape == ():\n            self.trace_dict[k][idx] = v\n        else:\n            self.trace_dict[k][idx, :] = v\n\n\nclass InferenceDataConverter:\n    """Encapsulate InferenceData specific logic."""\n\n    model: Model | None = None\n    posterior_predictive: Mapping[str, np.ndarray] | None = None\n    predictions: Mapping[str, np.ndarray] | None = None\n    prior: Mapping[str, np.ndarray] | None = None\n\n    def __init__(\n        self,\n        *,\n        trace=None,\n        prior=None,\n        posterior_predictive=None,\n        log_likelihood=False,\n        log_prior=False,\n        predictions=None,\n        coords: CoordSpec | None = None,\n        dims: DimSpec | None = None,\n        sample_dims: list | None = None,\n        model=None,\n        save_warmup: bool | None = None,\n        include_transformed: bool = False,\n    ):\n        self.save_warmup = rcParams["data.save_warmup"] if save_warmup is None else save_warmup\n        self.include_transformed = include_transformed\n        self.trace = trace\n\n        # this permits us to get the model from command-line argument or from with model:\n        self.model = modelcontext(model)\n\n        self.attrs = None\n        if trace is not None:\n            self.nchains = trace.nchains if hasattr(trace, "nchains") else 1\n            if hasattr(trace.report, "n_draws") and trace.report.n_draws is not None:\n                self.ndraws = trace.report.n_draws\n                self.attrs = {\n                    "sampling_time": trace.report.t_sampling,\n                    "tuning_steps": trace.report.n_tune,\n                }\n            else:\n                self.ndraws = len(trace)\n                if self.save_warmup:\n                    warnings.warn(\n                        "Warmup samples will be stored in posterior group and will not be"\n                        " excluded from stats and diagnostics."\n                        " Do not slice the trace manually before conversion",\n                        UserWarning,\n                    )\n            self.ntune = len(self.trace) - self.ndraws\n            self.posterior_trace, self.warmup_trace = self.split_trace()\n        else:\n            self.nchains = self.ndraws = 0\n\n        self.prior = prior\n        self.posterior_predictive = posterior_predictive\n        self.log_likelihood = log_likelihood\n        self.log_prior = log_prior\n        self.predictions = predictions\n\n        if all(elem is None for elem in (trace, predictions, posterior_predictive, prior)):\n            raise ValueError(\n                "When constructing InferenceData you must pass at least"\n                " one of trace, prior, posterior_predictive or predictions."\n            )\n\n        user_coords = {} if coords is None else coords\n        user_dims = {} if dims is None else dims\n        model_coords, model_dims = coords_and_dims_for_inferencedata(self.model)\n        self.coords = {**model_coords, **user_coords}\n        self.dims = {**model_dims, **user_dims}\n\n        if sample_dims is None:\n            sample_dims = ["chain", "draw"]\n        self.sample_dims = sample_dims\n\n        self.observations = find_observations(self.model)\n\n    def split_trace(self) -> tuple[Union[None, "MultiTrace"], Union[None, "MultiTrace"]]:\n        """Split MultiTrace object into posterior and warmup.\n\n        Returns\n        -------\n        trace_posterior: MultiTrace or None\n            The slice of the trace corresponding to the posterior. If the posterior\n            trace is empty, None is returned\n        trace_warmup: MultiTrace or None\n            The slice of the trace corresponding to the warmup. If the warmup trace is\n            empty or ``save_warmup=False``, None is returned\n        """\n        trace_posterior = None\n        trace_warmup = None\n        if self.save_warmup and self.ntune > 0:\n            trace_warmup = self.trace[: self.ntune]\n        if self.ndraws > 0:\n            trace_posterior = self.trace[self.ntune :]\n        return trace_posterior, trace_warmup\n\n    @requires("trace")\n    def posterior_to_xarray(self):\n        """Convert the posterior to an xarray dataset."""\n        var_names = get_default_varnames(\n            self.trace.varnames, include_transformed=self.include_transformed\n        )\n        data = {}\n        data_warmup = {}\n        for var_name in var_names:\n            if self.warmup_trace:\n                data_warmup[var_name] = np.array(\n                    self.warmup_trace.get_values(var_name, combine=False, squeeze=False)\n                )\n            if self.posterior_trace:\n                data[var_name] = np.array(\n                    self.posterior_trace.get_values(var_name, combine=False, squeeze=False)\n                )\n        return (\n            dict_to_dataset(\n                data,\n                library=pymc,\n                coords=self.coords,\n                dims=self.dims,\n                attrs=self.attrs,\n            ),\n            dict_to_dataset(\n                data_warmup,\n                library=pymc,\n                coords=self.coords,\n                dims=self.dims,\n                attrs=self.attrs,\n            ),\n        )\n\n    @requires("trace")\n    def sample_stats_to_xarray(self):\n        """Extract sample_stats from PyMC trace."""\n        data = {}\n        rename_key = {\n            "model_logp": "lp",\n            "mean_tree_accept": "acceptance_rate",\n            "depth": "tree_depth",\n            "tree_size": "n_steps",\n        }\n        data = {}\n        data_warmup = {}\n        for stat in self.trace.stat_names:\n            name = rename_key.get(stat, stat)\n            if name == "tune":\n                continue\n            if self.warmup_trace:\n                data_warmup[name] = np.array(\n                    self.warmup_trace.get_sampler_stats(stat, combine=False, squeeze=False)\n                )\n            if self.posterior_trace:\n                data[name] = np.array(\n                    self.posterior_trace.get_sampler_stats(stat, combine=False, squeeze=False)\n                )\n\n        return (\n            dict_to_dataset(\n                data,\n                library=pymc,\n                dims=None,\n                coords=self.coords,\n                attrs=self.attrs,\n            ),\n            dict_to_dataset(\n                data_warmup,\n                library=pymc,\n                dims=None,\n                coords=self.coords,\n                attrs=self.attrs,\n            ),\n        )\n\n    @requires(["posterior_predictive"])\n    def posterior_predictive_to_xarray(self):\n        """Convert posterior_predictive samples to xarray."""\n        data = self.posterior_predictive\n        dims = {var_name: self.sample_dims + self.dims.get(var_name, []) for var_name in data}\n        return dict_to_dataset(\n            data, library=pymc, coords=self.coords, dims=dims, default_dims=self.sample_dims\n        )\n\n    @requires(["predictions"])\n    def predictions_to_xarray(self):\n        """Convert predictions (out of sample predictions) to xarray."""\n        data = self.predictions\n        dims = {var_name: self.sample_dims + self.dims.get(var_name, []) for var_name in data}\n        return dict_to_dataset(\n            data, library=pymc, coords=self.coords, dims=dims, default_dims=self.sample_dims\n        )\n\n    def priors_to_xarray(self):\n        """Convert prior samples (and if possible prior predictive too) to xarray."""\n        if self.prior is None:\n            return {"prior": None, "prior_predictive": None}\n        if self.observations is not None:\n            prior_predictive_vars = list(set(self.observations).intersection(self.prior))\n            prior_vars = [key for key in self.prior.keys() if key not in prior_predictive_vars]\n        else:\n            prior_vars = list(self.prior.keys())\n            prior_predictive_vars = None\n\n        priors_dict = {}\n        for group, var_names in zip(\n            ("prior", "prior_predictive"), (prior_vars, prior_predictive_vars)\n        ):\n            priors_dict[group] = (\n                None\n                if var_names is None\n                else dict_to_dataset(\n                    {k: np.expand_dims(self.prior[k], 0) for k in var_names},\n                    library=pymc,\n                    coords=self.coords,\n                    dims=self.dims,\n                )\n            )\n        return priors_dict\n\n    @requires("observations")\n    @requires("model")\n    def observed_data_to_xarray(self):\n        """Convert observed data to xarray."""\n        if self.predictions:\n            return None\n        return dict_to_dataset(\n            self.observations,\n            library=pymc,\n            coords=self.coords,\n            dims=self.dims,\n            default_dims=[],\n        )\n\n    @requires("model")\n    def constant_data_to_xarray(self):\n        """Convert constant data to xarray."""\n        constant_data = find_constants(self.model)\n        if not constant_data:\n            return None\n\n        xarray_dataset = dict_to_dataset(\n            constant_data,\n            library=pymc,\n            coords=self.coords,\n            dims=self.dims,\n            default_dims=[],\n        )\n\n        # provisional handling of scalars in constant\n        # data to prevent promotion to rank 1\n        # in the future this will be handled by arviz\n        scalars = [var_name for var_name, value in constant_data.items() if np.ndim(value) == 0]\n        for s in scalars:\n            s_dim_0_name = f"{s}_dim_0"\n            xarray_dataset = xarray_dataset.squeeze(s_dim_0_name, drop=True)\n\n        return xarray_dataset\n\n    def to_inference_data(self):\n        """Convert all available data to an InferenceData object.\n\n        Note that if groups can not be created (e.g., there is no `trace`, so\n        the `posterior` and `sample_stats` can not be extracted), then the InferenceData\n        will not have those groups.\n        """\n        id_dict = {\n            "posterior": self.posterior_to_xarray(),\n            "sample_stats": self.sample_stats_to_xarray(),\n            "posterior_predictive": self.posterior_predictive_to_xarray(),\n            "predictions": self.predictions_to_xarray(),\n            **self.priors_to_xarray(),\n            "observed_data": self.observed_data_to_xarray(),\n        }\n        if self.predictions:\n            id_dict["predictions_constant_data"] = self.constant_data_to_xarray()\n        else:\n            id_dict["constant_data"] = self.constant_data_to_xarray()\n        idata = InferenceData(save_warmup=self.save_warmup, **id_dict)\n        if self.log_likelihood:\n            from pymc.stats.log_density import compute_log_likelihood\n\n            idata = compute_log_likelihood(\n                idata,\n                var_names=None if self.log_likelihood is True else self.log_likelihood,\n                extend_inferencedata=True,\n                model=self.model,\n                sample_dims=self.sample_dims,\n                progressbar=False,\n            )\n        if self.log_prior:\n            from pymc.stats.log_density import compute_log_prior\n\n            idata = compute_log_prior(\n                idata,\n                var_names=None if self.log_prior is True else self.log_prior,\n                extend_inferencedata=True,\n                model=self.model,\n                sample_dims=self.sample_dims,\n                progressbar=False,\n            )\n        return idata\n\n\ndef to_inference_data(\n    trace: Optional["MultiTrace"] = None,\n    *,\n    prior: Mapping[str, Any] | None = None,\n    posterior_predictive: Mapping[str, Any] | None = None,\n    log_likelihood: bool | Iterable[str] = False,\n    log_prior: bool | Iterable[str] = False,\n    coords: CoordSpec | None = None,\n    dims: DimSpec | None = None,\n    sample_dims: list | None = None,\n    model: Optional["Model"] = None,\n    save_warmup: bool | None = None,\n    include_transformed: bool = False,\n) -> InferenceData:\n    """Convert pymc data into an InferenceData object.\n\n    All three of them are optional arguments, but at least one of ``trace``,\n    ``prior`` and ``posterior_predictive`` must be present.\n    For a usage example read the\n    :ref:`Creating InferenceData section on from_pymc <creating_InferenceData>`\n\n    Parameters\n    ----------\n    trace : MultiTrace, optional\n        Trace generated from MCMC sampling. Output of\n        :func:`~pymc.sampling.sample`.\n    prior : dict, optional\n        Dictionary with the variable names as keys, and values numpy arrays\n        containing prior and prior predictive samples.\n    posterior_predictive : dict, optional\n        Dictionary with the variable names as keys, and values numpy arrays\n        containing posterior predictive samples.\n    log_likelihood : bool or array_like of str, optional\n        List of variables to calculate `log_likelihood`. Defaults to False.\n        If set to True, computes `log_likelihood` for all observed variables.\n    log_prior : bool or array_like of str, optional\n        List of variables to calculate `log_prior`. Defaults to False.\n        If set to True, computes `log_prior` for all unobserved variables.\n    coords : dict of {str: array-like}, optional\n        Map of coordinate names to coordinate values\n    dims : dict of {str: list of str}, optional\n        Map of variable names to the coordinate names to use to index its dimensions.\n    model : Model, optional\n        Model used to generate ``trace``. It is not necessary to pass ``model`` if in\n        ``with`` context.\n    save_warmup : bool, optional\n        Save warmup iterations InferenceData object. If not defined, use default\n        defined by the rcParams.\n    include_transformed : bool, optional\n        Save the transformed parameters in the InferenceData object. By default, these are\n        not saved.\n\n    Returns\n    -------\n    arviz.InferenceData\n    """\n    if isinstance(trace, InferenceData):\n        return trace\n\n    return InferenceDataConverter(\n        trace=trace,\n        prior=prior,\n        posterior_predictive=posterior_predictive,\n        log_likelihood=log_likelihood,\n        log_prior=log_prior,\n        coords=coords,\n        dims=dims,\n        sample_dims=sample_dims,\n        model=model,\n        save_warmup=save_warmup,\n        include_transformed=include_transformed,\n    ).to_inference_data()\n\n\n### Later I could have this return ``None`` if the ``idata_orig`` argument is supplied.  But\n### perhaps we should have an inplace argument?\ndef predictions_to_inference_data(\n    predictions,\n    posterior_trace: Optional["MultiTrace"] = None,\n    model: Optional["Model"] = None,\n    coords: CoordSpec | None = None,\n    dims: DimSpec | None = None,\n    sample_dims: list | None = None,\n    idata_orig: InferenceData | None = None,\n    inplace: bool = False,\n) -> InferenceData:\n    """Translate out-of-sample predictions into ``InferenceData``.\n\n    Parameters\n    ----------\n    predictions: Dict[str, np.ndarray]\n        The predictions are the return value of :func:`~pymc.sample_posterior_predictive`,\n        a dictionary of strings (variable names) to numpy ndarrays (draws).\n        Requires the arrays to follow the convention ``chain, draw, *shape``.\n    posterior_trace: MultiTrace\n        This should be a trace that has been thinned appropriately for\n        ``pymc.sample_posterior_predictive``. Specifically, any variable whose shape is\n        a deterministic function of the shape of any predictor (explanatory, independent, etc.)\n        variables must be *removed* from this trace.\n    model: Model\n        The pymc model. It can be omitted if within a model context.\n    coords: Dict[str, array-like[Any]]\n        Coordinates for the variables.  Map from coordinate names to coordinate values.\n    dims: Dict[str, array-like[str]]\n        Map from variable name to ordered set of coordinate names.\n    idata_orig: InferenceData, optional\n        If supplied, then modify this inference data in place, adding ``predictions`` and\n        (if available) ``predictions_constant_data`` groups. If this is not supplied, make a\n        fresh InferenceData\n    inplace: boolean, optional\n        If idata_orig is supplied and inplace is True, merge the predictions into idata_orig,\n        rather than returning a fresh InferenceData object.\n\n    Returns\n    -------\n    InferenceData:\n        May be modified ``idata_orig``.\n    """\n    if inplace and not idata_orig:\n        raise ValueError(\n            "Do not pass True for inplace unless passing an existing InferenceData as idata_orig"\n        )\n    converter = InferenceDataConverter(\n        trace=posterior_trace,\n        predictions=predictions,\n        model=model,\n        coords=coords,\n        dims=dims,\n        sample_dims=sample_dims,\n        log_likelihood=False,\n    )\n    if hasattr(idata_orig, "posterior"):\n        assert idata_orig is not None\n        converter.nchains = idata_orig["posterior"].sizes["chain"]\n        converter.ndraws = idata_orig["posterior"].sizes["draw"]\n    else:\n        aelem = next(iter(predictions.values()))\n        converter.nchains, converter.ndraws = aelem.shape[:2]\n    new_idata = converter.to_inference_data()\n    if idata_orig is None:\n        return new_idata\n    elif inplace:\n        concat([idata_orig, new_idata], dim=None, inplace=True)\n        return idata_orig\n    else:\n        # if we are not returning in place, then merge the old groups into the new inference\n        # data and return that.\n        concat([new_idata, idata_orig], dim=None, copy=True, inplace=True)\n        return new_idata\n\n\ndef dataset_to_point_list(\n    ds: xarray.Dataset | dict[str, xarray.DataArray], sample_dims: Sequence[str]\n) -> tuple[list[dict[str, np.ndarray]], dict[str, Any]]:\n    # All keys of the dataset must be a str\n    var_names = cast(list[str], list(ds.keys()))\n    for vn in var_names:\n        if not isinstance(vn, str):\n            raise ValueError(f"Variable names must be str, but dataset key {vn} is a {type(vn)}.")\n    num_sample_dims = len(sample_dims)\n    stacked_dims = {dim_name: ds[var_names[0]][dim_name] for dim_name in sample_dims}\n    transposed_dict = {vn: da.transpose(*sample_dims, ...) for vn, da in ds.items()}\n    stacked_dict = {\n        vn: da.values.reshape((-1, *da.shape[num_sample_dims:]))\n        for vn, da in transposed_dict.items()\n    }\n    points = [\n        {vn: stacked_dict[vn][i, ...] for vn in var_names}\n        for i in range(np.prod([len(coords) for coords in stacked_dims.values()]))\n    ]\n    # use the list of points\n    return cast(list[dict[str, np.ndarray]], points), stacked_dims\n\n\ndef apply_function_over_dataset(\n    fn: PointFunc,\n    dataset: Dataset,\n    *,\n    output_var_names: Sequence[str],\n    coords,\n    dims,\n    sample_dims: Sequence[str] = ("chain", "draw"),\n    progressbar: bool = True,\n    progressbar_theme: Theme | None = default_progress_theme,\n) -> Dataset:\n    posterior_pts, stacked_dims = dataset_to_point_list(dataset, sample_dims)\n\n    n_pts = len(posterior_pts)\n    out_dict = _DefaultTrace(n_pts)\n    indices = range(n_pts)\n\n    with CustomProgress(\n        console=Console(theme=progressbar_theme), disable=not progressbar\n    ) as progress:\n        task = progress.add_task("Computing ...", total=n_pts)\n        for idx in indices:\n            out = fn(posterior_pts[idx])\n            fn.f.trust_input = True  # If we arrive here the dtypes are valid\n            for var_name, val in zip(output_var_names, out, strict=True):\n                out_dict.insert(var_name, val, idx)\n\n            progress.advance(task)\n        progress.update(task, refresh=True, completed=n_pts)\n\n    out_trace = out_dict.trace_dict\n    for key, val in out_trace.items():\n        out_trace[key] = val.reshape(\n            (\n                *[len(coord) for coord in stacked_dims.values()],\n                *val.shape[1:],\n            )\n        )\n\n    return dict_to_dataset(\n        out_trace,\n        library=pymc,\n        dims=dims,\n        coords=coords,\n        default_dims=list(sample_dims),\n        skip_event_dims=True,\n    )\n',
            'tests/backends/test_arviz.py': '#   Copyright 2024 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\nimport warnings\n\nimport numpy as np\nimport pytensor.tensor as pt\nimport pytest\nimport xarray\n\nfrom arviz import InferenceData\nfrom arviz.tests.helpers import check_multiple_attrs\nfrom numpy import ma\nfrom pytensor.tensor.subtensor import AdvancedIncSubtensor, AdvancedIncSubtensor1\n\nimport pymc as pm\n\nfrom pymc.backends.arviz import (\n    InferenceDataConverter,\n    dataset_to_point_list,\n    predictions_to_inference_data,\n    to_inference_data,\n)\nfrom pymc.exceptions import ImputationWarning\n\n# Turn all warnings into errors for this module\npytestmark = pytest.mark.filterwarnings(\n    "error",\n    # Related to https://github.com/arviz-devs/arviz/issues/2327\n    "ignore:datetime.datetime.utcnow():DeprecationWarning",\n)\n\n\n@pytest.fixture(scope="module")\ndef eight_schools_params():\n    """Share setup for eight schools."""\n    return {\n        "J": 8,\n        "y": np.array([28.0, 8.0, -3.0, 7.0, -1.0, 1.0, 18.0, 12.0]),\n        "sigma": np.array([15.0, 10.0, 16.0, 11.0, 9.0, 11.0, 10.0, 18.0]),\n    }\n\n\n@pytest.fixture(scope="module")\ndef draws():\n    """Share default draw count."""\n    return 500\n\n\n@pytest.fixture(scope="module")\ndef chains():\n    """Share default chain count."""\n    return 2\n\n\nclass TestDataPyMC:\n    class Data:\n        def __init__(self, model, trace):\n            self.model = model\n            self.obj = trace\n\n    @pytest.fixture(scope="class")\n    def data(self, eight_schools_params, draws, chains):\n        with pm.Model() as model:\n            mu = pm.Normal("mu", mu=0, sigma=5)\n            tau = pm.HalfCauchy("tau", beta=5)\n            eta = pm.Normal("eta", mu=0, sigma=1, size=eight_schools_params["J"])\n            theta = pm.Deterministic("theta", mu + tau * eta)\n            pm.Normal(\n                "obs",\n                mu=theta,\n                sigma=eight_schools_params["sigma"],\n                observed=eight_schools_params["y"],\n            )\n            trace = pm.sample(\n                draws,\n                chains=chains,\n                return_inferencedata=False,\n            )\n\n        return self.Data(model, trace)\n\n    def get_inference_data(self, data, eight_schools_params):\n        with data.model:\n            prior = pm.sample_prior_predictive(return_inferencedata=False)\n            posterior_predictive = pm.sample_posterior_predictive(\n                data.obj, return_inferencedata=False\n            )\n\n        return to_inference_data(\n            trace=data.obj,\n            prior=prior,\n            posterior_predictive=posterior_predictive,\n            log_likelihood=True,\n            coords={"school": np.arange(eight_schools_params["J"])},\n            dims={"theta": ["school"], "eta": ["school"]},\n            model=data.model,\n        )\n\n    def get_predictions_inference_data(\n        self, data, eight_schools_params, inplace\n    ) -> tuple[InferenceData, dict[str, np.ndarray]]:\n        with data.model:\n            prior = pm.sample_prior_predictive(return_inferencedata=False)\n            posterior_predictive = pm.sample_posterior_predictive(\n                data.obj, return_inferencedata=False\n            )\n\n            idata = to_inference_data(\n                trace=data.obj,\n                prior=prior,\n                coords={"school": np.arange(eight_schools_params["J"])},\n                dims={"theta": ["school"], "eta": ["school"]},\n            )\n            assert isinstance(idata, InferenceData)\n            extended = predictions_to_inference_data(\n                posterior_predictive, idata_orig=idata, inplace=inplace\n            )\n            assert isinstance(extended, InferenceData)\n            assert (id(idata) == id(extended)) == inplace\n        return (extended, posterior_predictive)\n\n    def make_predictions_inference_data(\n        self, data, eight_schools_params\n    ) -> tuple[InferenceData, dict[str, np.ndarray]]:\n        with data.model:\n            posterior_predictive = pm.sample_posterior_predictive(\n                data.obj, return_inferencedata=False\n            )\n            idata = predictions_to_inference_data(\n                posterior_predictive,\n                posterior_trace=data.obj,\n                coords={"school": np.arange(eight_schools_params["J"])},\n                dims={"theta": ["school"], "eta": ["school"]},\n            )\n            assert isinstance(idata, InferenceData)\n        return idata, posterior_predictive\n\n    def test_to_idata(self, data, eight_schools_params, chains, draws):\n        inference_data = self.get_inference_data(data, eight_schools_params)\n        test_dict = {\n            "posterior": ["mu", "tau", "eta", "theta"],\n            "sample_stats": ["diverging", "lp", "~log_likelihood"],\n            "log_likelihood": ["obs"],\n            "posterior_predictive": ["obs"],\n            "prior": ["mu", "tau", "eta", "theta"],\n            "prior_predictive": ["obs"],\n            "observed_data": ["obs"],\n        }\n        fails = check_multiple_attrs(test_dict, inference_data)\n        assert not fails\n        chains = inference_data.posterior.sizes["chain"]\n        draws = inference_data.posterior.sizes["draw"]\n        obs = inference_data.observed_data["obs"]\n        assert inference_data.log_likelihood["obs"].shape == (chains, draws, *obs.shape)\n\n    def test_predictions_to_idata(self, data, eight_schools_params):\n        "Test that we can add predictions to a previously-existing InferenceData."\n        test_dict = {\n            "posterior": ["mu", "tau", "eta", "theta"],\n            "sample_stats": ["diverging", "lp"],\n            "predictions": ["obs"],\n            "prior": ["mu", "tau", "eta", "theta"],\n            "observed_data": ["obs"],\n        }\n\n        # check adding non-destructively\n        inference_data, _ = self.get_predictions_inference_data(data, eight_schools_params, False)\n        fails = check_multiple_attrs(test_dict, inference_data)\n        assert not fails\n        for key, ivalues in inference_data.predictions.items():\n            assert (\n                len(ivalues["chain"]) == inference_data.posterior.sizes["chain"]\n            )  # same chains as in posterior\n\n        # check adding in place\n        inference_data, posterior_predictive = self.get_predictions_inference_data(\n            data, eight_schools_params, True\n        )\n        fails = check_multiple_attrs(test_dict, inference_data)\n        assert not fails\n        for key, ivalues in inference_data.predictions.items():\n            assert (\n                len(ivalues["chain"]) == inference_data.posterior.sizes["chain"]\n            )  # same chains as in posterior\n\n    def test_predictions_to_idata_new(self, data, eight_schools_params):\n        # check creating new\n        inference_data, posterior_predictive = self.make_predictions_inference_data(\n            data, eight_schools_params\n        )\n        test_dict = {\n            "posterior": ["mu", "tau", "eta", "theta"],\n            "predictions": ["obs"],\n            "~observed_data": "",\n        }\n        fails = check_multiple_attrs(test_dict, inference_data)\n        assert not fails\n        for key, values in posterior_predictive.items():\n            ivalues = inference_data.predictions[key]\n            assert (len(ivalues["chain"]) == 2) and (len(ivalues["draw"]) == 500)\n\n    def test_posterior_predictive_keep_size(self, data, chains, draws, eight_schools_params):\n        with data.model:\n            posterior_predictive = pm.sample_posterior_predictive(\n                data.obj, return_inferencedata=False\n            )\n            inference_data = to_inference_data(\n                trace=data.obj,\n                posterior_predictive=posterior_predictive,\n                coords={"school": np.arange(eight_schools_params["J"])},\n                dims={"theta": ["school"], "eta": ["school"]},\n            )\n\n        shape = inference_data.posterior_predictive.obs.shape\n        assert np.all(\n            [obs_s == s for obs_s, s in zip(shape, (chains, draws, eight_schools_params["J"]))]\n        )\n\n    def test_posterior_predictive_thinned(self, data):\n        with data.model:\n            draws = 20\n            thin_by = 4\n            with warnings.catch_warnings():\n                warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n                idata = pm.sample(tune=5, draws=draws, chains=2, return_inferencedata=True)\n            thinned_idata = idata.sel(draw=slice(None, None, thin_by))\n            idata.extend(pm.sample_posterior_predictive(thinned_idata))\n        test_dict = {\n            "posterior": ["mu", "tau", "eta", "theta"],\n            "sample_stats": ["diverging", "lp", "~log_likelihood"],\n            "posterior_predictive": ["obs"],\n            "observed_data": ["obs"],\n        }\n        fails = check_multiple_attrs(test_dict, idata)\n        assert not fails\n        assert idata.posterior.sizes["chain"] == 2\n        assert idata.posterior.sizes["draw"] == draws\n        assert idata.posterior_predictive.sizes["chain"] == 2\n        assert idata.posterior_predictive.sizes["draw"] == draws / thin_by\n        assert np.allclose(idata.posterior["draw"], np.arange(draws))\n        assert np.allclose(idata.posterior_predictive["draw"], np.arange(draws, step=thin_by))\n\n    @pytest.mark.parametrize("use_context", [True, False])\n    def test_autodetect_coords_from_model(self, use_context):\n        pd = pytest.importorskip("pandas")\n        df_data = pd.DataFrame(columns=["date"]).set_index("date")\n        dates = pd.date_range(start="2020-05-01", end="2020-05-20")\n        for city, mu in {"Berlin": 15, "San Marino": 18, "Paris": 16}.items():\n            df_data[city] = np.random.normal(loc=mu, size=len(dates))\n        df_data.index = dates\n        df_data.index.name = "date"\n\n        coords = {"date": df_data.index, "city": df_data.columns}\n        with pm.Model(coords=coords) as model:\n            europe_mean = pm.Normal("europe_mean_temp", mu=15.0, sigma=3.0)\n            city_offset = pm.Normal("city_offset", mu=0.0, sigma=3.0, dims="city")\n            city_temperature = pm.Deterministic(\n                "city_temperature", europe_mean + city_offset, dims="city"\n            )\n\n            data_dims = ("date", "city")\n            data = pm.Data("data", df_data, dims=data_dims)\n            _ = pm.Normal(\n                "likelihood", mu=city_temperature, sigma=0.5, observed=data, dims=data_dims\n            )\n\n            trace = pm.sample(\n                return_inferencedata=False,\n                compute_convergence_checks=False,\n                cores=1,\n                chains=1,\n                tune=20,\n                draws=30,\n                step=pm.Metropolis(),\n            )\n            if use_context:\n                with warnings.catch_warnings():\n                    warnings.filterwarnings("ignore", "More chains .* than draws.*", UserWarning)\n                    idata = to_inference_data(trace=trace)\n        if not use_context:\n            with warnings.catch_warnings():\n                warnings.filterwarnings("ignore", "More chains .* than draws.*", UserWarning)\n                idata = to_inference_data(trace=trace, model=model)\n\n        assert "city" in list(idata.posterior.dims)\n        assert "city" in list(idata.observed_data.dims)\n        assert "date" in list(idata.observed_data.dims)\n\n        np.testing.assert_array_equal(idata.posterior.coords["city"], coords["city"])\n        np.testing.assert_array_equal(idata.observed_data.coords["date"], coords["date"])\n        np.testing.assert_array_equal(idata.observed_data.coords["city"], coords["city"])\n\n    def test_overwrite_model_coords_dims(self):\n        """Check coords and dims from model object can be partially overwritten."""\n        dim1 = ["a", "b"]\n        new_dim1 = ["c", "d"]\n        coords = {"dim1": dim1, "dim2": ["c1", "c2"]}\n        x_data = np.arange(4).reshape((2, 2))\n        y = x_data + np.random.normal(size=(2, 2))\n        with pm.Model(coords=coords):\n            x = pm.Data("x", x_data, dims=("dim1", "dim2"))\n            beta = pm.Normal("beta", 0, 1, dims="dim1")\n            _ = pm.Normal("obs", x * beta, 1, observed=y, dims=("dim1", "dim2"))\n            trace = pm.sample(100, tune=100, return_inferencedata=False)\n            idata1 = to_inference_data(trace)\n            idata2 = to_inference_data(trace, coords={"dim1": new_dim1}, dims={"beta": ["dim2"]})\n\n        test_dict = {"posterior": ["beta"], "observed_data": ["obs"], "constant_data": ["x"]}\n        fails1 = check_multiple_attrs(test_dict, idata1)\n        assert not fails1\n        fails2 = check_multiple_attrs(test_dict, idata2)\n        assert not fails2\n        assert "dim1" in list(idata1.posterior.beta.dims)\n        assert "dim2" in list(idata2.posterior.beta.dims)\n        assert np.all(idata1.constant_data.x.dim1.values == np.array(dim1))\n        assert np.all(idata1.constant_data.x.dim2.values == np.array(["c1", "c2"]))\n        assert np.all(idata2.constant_data.x.dim1.values == np.array(new_dim1))\n        assert np.all(idata2.constant_data.x.dim2.values == np.array(["c1", "c2"]))\n\n    def test_missing_data_model(self):\n        # source tests/test_missing.py\n        data = ma.masked_values([1, 2, -1, 4, -1], value=-1)\n        model = pm.Model()\n        with model:\n            x = pm.Normal("x", 1, 1)\n            with pytest.warns(ImputationWarning):\n                y = pm.Normal("y", x, 1, observed=data)\n            inference_data = pm.sample(\n                100, chains=2, return_inferencedata=True, idata_kwargs={"log_likelihood": True}\n            )\n\n        # make sure that data is really missing\n        assert "y_unobserved" in model.named_vars\n\n        test_dict = {\n            "posterior": ["x", "y_unobserved"],\n            "observed_data": ["y_observed"],\n            "log_likelihood": ["y_observed"],\n        }\n        fails = check_multiple_attrs(test_dict, inference_data)\n        assert not fails\n\n        # The missing part of partial observed RVs is not included in log_likelihood\n        # See https://github.com/pymc-devs/pymc/issues/5255\n        assert inference_data.log_likelihood["y_observed"].shape == (2, 100, 3)\n\n    def test_mv_missing_data_model(self):\n        data = ma.masked_values([[1, 2], [2, 2], [-1, 4], [2, -1], [-1, -1]], value=-1)\n\n        model = pm.Model()\n        with model:\n            mu = pm.Normal("mu", 0, 1, size=2)\n            sd_dist = pm.HalfNormal.dist(1.0, size=2)\n            chol, *_ = pm.LKJCholeskyCov("chol_cov", n=2, eta=1, sd_dist=sd_dist)\n            with pytest.warns(ImputationWarning):\n                y = pm.MvNormal("y", mu=mu, chol=chol, observed=data)\n            inference_data = pm.sample(\n                tune=10,\n                draws=10,\n                chains=2,\n                step=pm.Metropolis(),\n                idata_kwargs={"log_likelihood": True},\n            )\n\n        # make sure that data is really missing\n        assert isinstance(y.owner.inputs[0].owner.op, AdvancedIncSubtensor | AdvancedIncSubtensor1)\n\n        test_dict = {\n            "posterior": ["mu", "chol_cov"],\n            "observed_data": ["y_observed"],\n            "log_likelihood": ["y_observed"],\n        }\n        fails = check_multiple_attrs(test_dict, inference_data)\n        assert not fails\n\n    @pytest.mark.parametrize("log_likelihood", [True, False, ["y1"]])\n    def test_multiple_observed_rv(self, log_likelihood):\n        y1_data = np.random.randn(10)\n        y2_data = np.random.randn(100)\n        with pm.Model():\n            x = pm.Normal("x", 1, 1)\n            pm.Normal("y1", x, 1, observed=y1_data)\n            pm.Normal("y2", x, 1, observed=y2_data)\n            inference_data = pm.sample(\n                100,\n                chains=2,\n                return_inferencedata=True,\n                idata_kwargs={"log_likelihood": log_likelihood},\n            )\n        test_dict = {\n            "posterior": ["x"],\n            "observed_data": ["y1", "y2"],\n            "log_likelihood": ["y1", "y2"],\n            "sample_stats": ["diverging", "lp", "~log_likelihood"],\n        }\n        if not log_likelihood:\n            test_dict.pop("log_likelihood")\n            test_dict["~log_likelihood"] = []\n        elif isinstance(log_likelihood, list):\n            test_dict["log_likelihood"] = ["y1", "~y2"]\n            assert inference_data.log_likelihood["y1"].shape == (2, 100, 10)\n        else:\n            assert inference_data.log_likelihood["y1"].shape == (2, 100, 10)\n            assert inference_data.log_likelihood["y2"].shape == (2, 100, 100)\n\n        fails = check_multiple_attrs(test_dict, inference_data)\n        assert not fails\n\n    def test_single_observation(self):\n        with pm.Model():\n            p = pm.Uniform("p", 0, 1)\n            pm.Binomial("w", p=p, n=2, observed=[1])\n            inference_data = pm.sample(\n                500, chains=2, return_inferencedata=True, idata_kwargs={"log_likelihood": True}\n            )\n\n        assert inference_data\n        assert inference_data.log_likelihood["w"].shape == (2, 500, 1)\n\n    def test_potential(self):\n        with pm.Model():\n            x = pm.Normal("x", 0.0, 1.0)\n            pm.Potential("z", pm.logp(pm.Normal.dist(x, 1.0), np.random.randn(10)))\n            inference_data = pm.sample(100, chains=2, return_inferencedata=True)\n\n        assert inference_data\n\n    @pytest.mark.parametrize("use_context", [True, False])\n    def test_constant_data(self, use_context):\n        """Test constant_data group behaviour."""\n        with pm.Model() as model:\n            x = pm.Data("x", [1.0, 2.0, 3.0])\n            y = pm.Data("y", [1.0, 2.0, 3.0])\n            beta_sigma = pm.Data("beta_sigma", 1)\n            beta = pm.Normal("beta", 0, beta_sigma)\n            obs = pm.Normal("obs", x * beta, 1, observed=y)\n            trace = pm.sample(100, chains=2, tune=100, return_inferencedata=False)\n            if use_context:\n                inference_data = to_inference_data(trace=trace, log_likelihood=True)\n\n        if not use_context:\n            inference_data = to_inference_data(trace=trace, model=model, log_likelihood=True)\n        test_dict = {\n            "posterior": ["beta"],\n            "observed_data": ["obs"],\n            "constant_data": ["x", "beta_sigma"],\n        }\n        fails = check_multiple_attrs(test_dict, inference_data)\n        assert not fails\n        assert inference_data.log_likelihood["obs"].shape == (2, 100, 3)\n        # test that scalars are dimensionless in constant_data (issue #6755)\n        assert inference_data.constant_data["beta_sigma"].ndim == 0\n\n    @pytest.mark.parametrize("constant_in_generative_graph", [True, False])\n    def test_observed_data_also_constant(self, constant_in_generative_graph):\n        """Test that wen the same variable is used as constant data and observed data, it shows up in both groups."""\n        with pm.Model(coords={"trial": [0, 1, 2]}) as model:\n            x = pm.Data("x", [1.0, 2.0, 3.0], dims=["trial"])\n            sigma = pm.HalfNormal("sigma", 1)\n            mu = x - 1 if constant_in_generative_graph else 0\n            pm.Normal("y", mu, sigma, observed=x, dims=["trial"])\n\n            trace = pm.sample_prior_predictive(100, return_inferencedata=False)\n\n        inference_data = to_inference_data(prior=trace, model=model, log_likelihood=False)\n\n        test_dict = {\n            "prior": ["sigma"],\n            "observed_data": ["y"],\n        }\n        if constant_in_generative_graph:\n            test_dict["constant_data"] = ["x"]\n        else:\n            test_dict["~constant_data"] = []\n        fails = check_multiple_attrs(test_dict, inference_data)\n        assert not fails\n\n    def test_predictions_constant_data(self):\n        with pm.Model():\n            x = pm.Data("x", [1.0, 2.0, 3.0])\n            y = pm.Data("y", [1.0, 2.0, 3.0])\n            beta = pm.Normal("beta", 0, 1)\n            obs = pm.Normal("obs", x * beta, 1, observed=y)\n            trace = pm.sample(100, tune=100, return_inferencedata=False)\n            inference_data = to_inference_data(trace)\n\n        test_dict = {"posterior": ["beta"], "observed_data": ["obs"], "constant_data": ["x"]}\n        fails = check_multiple_attrs(test_dict, inference_data)\n        assert not fails\n\n        with pm.Model():\n            x = pm.Data("x", [1.0, 2.0])\n            y = pm.Data("y", [1.0, 2.0])\n            beta = pm.Normal("beta", 0, 1)\n            obs = pm.Normal("obs", x * beta, 1, observed=y)\n            predictive_trace = pm.sample_posterior_predictive(\n                inference_data, return_inferencedata=False\n            )\n            assert set(predictive_trace.keys()) == {"obs"}\n            # this should be four chains of 100 samples\n            # assert predictive_trace["obs"].shape == (400, 2)\n            # but the shape seems to vary between pymc versions\n            with warnings.catch_warnings():\n                warnings.filterwarnings("ignore", "More chains .* than draws.*", UserWarning)\n                inference_data = predictions_to_inference_data(\n                    predictive_trace, posterior_trace=trace\n                )\n        test_dict = {"posterior": ["beta"], "~observed_data": ""}\n        fails = check_multiple_attrs(test_dict, inference_data)\n        assert not fails, "Posterior data not copied over as expected."\n        test_dict = {"predictions": ["obs"]}\n        fails = check_multiple_attrs(test_dict, inference_data)\n        assert not fails, "Predictions not instantiated as expected."\n        test_dict = {"predictions_constant_data": ["x"]}\n        fails = check_multiple_attrs(test_dict, inference_data)\n        assert not fails, "Predictions constant data not instantiated as expected."\n\n    def test_no_trace(self):\n        with pm.Model() as model:\n            x = pm.Data("x", [1.0, 2.0, 3.0])\n            y = pm.Data("y", [1.0, 2.0, 3.0])\n            beta = pm.Normal("beta", 0, 1)\n            obs = pm.Normal("obs", x * beta, 1, observed=y)\n            idata = pm.sample(100, tune=100)\n            prior = pm.sample_prior_predictive(return_inferencedata=False)\n            posterior_predictive = pm.sample_posterior_predictive(idata, return_inferencedata=False)\n\n        # Only prior\n        inference_data = to_inference_data(prior=prior, model=model)\n        test_dict = {"prior": ["beta"], "prior_predictive": ["obs"]}\n        fails = check_multiple_attrs(test_dict, inference_data)\n        assert not fails\n        # Only posterior_predictive\n        inference_data = to_inference_data(posterior_predictive=posterior_predictive, model=model)\n        test_dict = {"posterior_predictive": ["obs"]}\n        fails = check_multiple_attrs(test_dict, inference_data)\n        assert not fails\n        # Prior and posterior_predictive but no trace\n        inference_data = to_inference_data(\n            prior=prior, posterior_predictive=posterior_predictive, model=model\n        )\n        test_dict = {\n            "prior": ["beta"],\n            "prior_predictive": ["obs"],\n            "posterior_predictive": ["obs"],\n        }\n        fails = check_multiple_attrs(test_dict, inference_data)\n        assert not fails\n\n    @pytest.mark.parametrize("use_context", [True, False])\n    def test_priors_separation(self, use_context):\n        """Test model is enough to get prior, prior predictive, constant_data and observed_data."""\n        with pm.Model() as model:\n            x = pm.Data("x", [1.0, 2.0, 3.0])\n            y = pm.Data("y", [1.0, 2.0, 3.0])\n            beta = pm.Normal("beta", 0, 1)\n            obs = pm.Normal("obs", x * beta, 1, observed=y)\n            prior = pm.sample_prior_predictive(return_inferencedata=False)\n\n        test_dict = {\n            "prior": ["beta", "~obs"],\n            "observed_data": ["obs"],\n            "prior_predictive": ["obs"],\n            "constant_data": ["x"],\n        }\n        if use_context:\n            with model:\n                inference_data = to_inference_data(prior=prior)\n        else:\n            inference_data = to_inference_data(prior=prior, model=model)\n        fails = check_multiple_attrs(test_dict, inference_data)\n        assert not fails\n\n    def test_conversion_from_variables_subset(self):\n        """This is a regression test for issue #5337."""\n        with pm.Model() as model:\n            x = pm.Normal("x")\n            pm.Normal("y", x, observed=5)\n            idata = pm.sample(\n                tune=10, draws=20, chains=1, step=pm.Metropolis(), compute_convergence_checks=False\n            )\n            pm.sample_posterior_predictive(idata, var_names=["x"])\n            pm.sample_prior_predictive(var_names=["x"])\n\n    def test_multivariate_observations(self):\n        coords = {"direction": ["x", "y", "z"], "experiment": np.arange(20)}\n        data = np.random.multinomial(20, [0.2, 0.3, 0.5], size=20)\n        with pm.Model(coords=coords):\n            p = pm.Beta("p", 1, 1, size=(3,))\n            p = p / p.sum()\n            pm.Multinomial("y", 20, p, dims=("experiment", "direction"), observed=data)\n            with warnings.catch_warnings():\n                warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n                idata = pm.sample(\n                    draws=50,\n                    chains=2,\n                    tune=100,\n                    return_inferencedata=True,\n                    idata_kwargs={"log_likelihood": True},\n                )\n        test_dict = {\n            "posterior": ["p"],\n            "sample_stats": ["lp"],\n            "log_likelihood": ["y"],\n            "observed_data": ["y"],\n        }\n        fails = check_multiple_attrs(test_dict, idata)\n        assert not fails\n        assert "direction" not in idata.log_likelihood.dims\n        assert "direction" in idata.observed_data.dims\n        assert idata.log_likelihood["y"].shape == (2, 50, 20)\n\n    def test_constant_data_coords_issue_5046(self):\n        """This is a regression test against a bug where a local coords variable was overwritten."""\n        dims = {"alpha": ["backwards"], "bravo": ["letters", "yesno"]}\n        coords = {\n            "backwards": np.arange(17)[::-1],\n            "letters": list("ABCDEFGHIJK"),\n            "yesno": ["yes", "no"],\n        }\n        data = {\n            name: np.random.uniform(size=[len(coords[dn]) for dn in dnames])\n            for name, dnames in dims.items()\n        }\n\n        for k in data:\n            assert len(data[k].shape) == len(dims[k])\n\n        ds = pm.backends.arviz.dict_to_dataset(\n            data=data, library=pm, coords=coords, dims=dims, default_dims=[], index_origin=0\n        )\n        for dname, cvals in coords.items():\n            np.testing.assert_array_equal(ds[dname].values, cvals)\n\n    def test_issue_5043_autoconvert_coord_values(self):\n        pd = pytest.importorskip("pandas")\n        coords = {"city": pd.Series(["Bonn", "Berlin"])}\n        with pm.Model(coords=coords) as pmodel:\n            # The model tracks coord values as (immutable) tuples\n            assert isinstance(pmodel.coords["city"], tuple)\n            pm.Normal("x", dims="city")\n            mtrace = pm.sample(\n                return_inferencedata=False,\n                compute_convergence_checks=False,\n                step=pm.Metropolis(),\n                cores=1,\n                tune=7,\n                draws=15,\n            )\n            # The converter must convert coord values them to numpy arrays\n            # because tuples as coordinate values causes problems with xarray.\n            converter = InferenceDataConverter(trace=mtrace)\n            assert isinstance(converter.coords["city"], np.ndarray)\n            converter.to_inference_data()\n\n            # We\'re not automatically converting things other than tuple,\n            # so advanced use cases remain supported at the InferenceData level.\n            # They just can\'t be used in the model construction already.\n            converter = InferenceDataConverter(\n                trace=mtrace,\n                coords={\n                    "city": pd.MultiIndex.from_tuples(\n                        [("Bonn", 53111), ("Berlin", 10178)], names=["name", "zipcode"]\n                    )\n                },\n            )\n            assert isinstance(converter.coords["city"], pd.MultiIndex)\n\n    def test_variable_dimension_name_collision(self):\n        with pytest.raises(ValueError, match="same name as its dimension"):\n            with pm.Model() as pmodel:\n                var = pt.as_tensor([1, 2, 3])\n                pmodel.register_rv(var, name="time", dims=("time",))\n\n    def test_include_transformed(self):\n        with pm.Model():\n            pm.Uniform("p", 0, 1)\n\n            # First check that the default is to exclude the transformed variables\n            sample_kwargs = {\n                "tune": 5,\n                "draws": 7,\n                "chains": 2,\n                "cores": 1,\n                "compute_convergence_checks": False,\n            }\n            inference_data = pm.sample(**sample_kwargs, step=pm.Metropolis())\n            assert "p_interval__" not in inference_data.posterior\n\n            # Now check that they are included when requested\n            inference_data = pm.sample(\n                **sample_kwargs,\n                step=pm.Metropolis(),\n                idata_kwargs={"include_transformed": True},\n            )\n            assert "p_interval__" in inference_data.posterior\n\n    @pytest.mark.filterwarnings(\n        "error",\n        # Related to https://github.com/arviz-devs/arviz/issues/2327\n        "ignore:datetime.datetime.utcnow():DeprecationWarning",\n    )\n    @pytest.mark.parametrize("chains", (1, 2))\n    def test_single_chain(self, chains):\n        # Test that no UserWarning is raised when sampling with NUTS defaults\n\n        # When this test was added, a `UserWarning: More chains (500) than draws (1)` used to be issued\n        # when sampling with a single chain\n        with pm.Model():\n            pm.Normal("x")\n            pm.sample(chains=chains, return_inferencedata=True)\n\n\nclass TestPyMCWarmupHandling:\n    @pytest.mark.parametrize("save_warmup", [False, True])\n    @pytest.mark.parametrize("chains", [1, 2])\n    @pytest.mark.parametrize("tune,draws", [(0, 50), (10, 40), (30, 0)])\n    def test_save_warmup(self, save_warmup, chains, tune, draws):\n        with pm.Model():\n            pm.Uniform("u1")\n            pm.Normal("n1")\n            with warnings.catch_warnings():\n                warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n                warnings.filterwarnings("ignore", "More chains .* than draws.*", UserWarning)\n                idata = pm.sample(\n                    tune=tune,\n                    draws=draws,\n                    chains=chains,\n                    cores=1,\n                    step=pm.Metropolis(),\n                    discard_tuned_samples=False,\n                    return_inferencedata=True,\n                    idata_kwargs={"save_warmup": save_warmup},\n                )\n        warmup_prefix = "" if save_warmup and (tune > 0) else "~"\n        post_prefix = "" if draws > 0 else "~"\n        test_dict = {\n            f"{post_prefix}posterior": ["u1", "n1"],\n            f"{post_prefix}sample_stats": ["~tune", "accept"],\n            f"{warmup_prefix}warmup_posterior": ["u1", "n1"],\n            f"{warmup_prefix}warmup_sample_stats": ["~tune"],\n            "~warmup_log_likelihood": [],\n            "~log_likelihood": [],\n        }\n        fails = check_multiple_attrs(test_dict, idata)\n        assert not fails\n        if hasattr(idata, "posterior"):\n            assert idata.posterior.sizes["chain"] == chains\n            assert idata.posterior.sizes["draw"] == draws\n        if hasattr(idata, "warmup_posterior"):\n            assert idata.warmup_posterior.sizes["chain"] == chains\n            assert idata.warmup_posterior.sizes["draw"] == tune\n\n    def test_save_warmup_issue_1208_after_3_9(self):\n        with pm.Model():\n            pm.Uniform("u1")\n            pm.Normal("n1")\n            with warnings.catch_warnings():\n                warnings.filterwarnings("ignore", "Tuning samples will be included.*", UserWarning)\n                trace = pm.sample(\n                    tune=100,\n                    draws=200,\n                    chains=2,\n                    cores=1,\n                    step=pm.Metropolis(),\n                    discard_tuned_samples=False,\n                    return_inferencedata=False,\n                )\n            assert isinstance(trace, pm.backends.base.MultiTrace)\n            assert len(trace) == 300\n\n            # from original trace, warmup draws should be separated out\n            idata = to_inference_data(trace, save_warmup=True)\n            test_dict = {\n                "posterior": ["u1", "n1"],\n                "sample_stats": ["~tune", "accept"],\n                "warmup_posterior": ["u1", "n1"],\n                "warmup_sample_stats": ["~tune", "accept"],\n            }\n            fails = check_multiple_attrs(test_dict, idata)\n            assert not fails\n            assert idata.posterior.sizes["chain"] == 2\n            assert idata.posterior.sizes["draw"] == 200\n\n            # manually sliced trace triggers the same warning as <=3.8\n            with pytest.warns(UserWarning, match="Warmup samples"):\n                idata = to_inference_data(trace[-30:], save_warmup=True)\n            test_dict = {\n                "posterior": ["u1", "n1"],\n                "sample_stats": ["~tune", "accept"],\n                "~warmup_posterior": [],\n                "~warmup_sample_stats": [],\n            }\n            fails = check_multiple_attrs(test_dict, idata)\n            assert not fails\n            assert idata.posterior.sizes["chain"] == 2\n            assert idata.posterior.sizes["draw"] == 30\n\n\nclass TestDatasetToPointList:\n    @pytest.mark.parametrize("input_type", ("dict", "Dataset"))\n    def test_dataset_to_point_list(self, input_type):\n        if input_type == "dict":\n            ds = {}\n        elif input_type == "Dataset":\n            ds = xarray.Dataset()\n        ds["A"] = xarray.DataArray([[1, 2, 3]] * 2, dims=("chain", "draw"))\n        pl, _ = dataset_to_point_list(ds, sample_dims=["chain", "draw"])\n        assert isinstance(pl, list)\n        assert len(pl) == 6\n        assert isinstance(pl[0], dict)\n        assert isinstance(pl[0]["A"], np.ndarray)\n\n    def test_transposed_dataset_to_point_list(self):\n        ds = xarray.Dataset()\n        ds["A"] = xarray.DataArray([[[1, 2, 3], [2, 3, 4]]] * 5, dims=("team", "draw", "chain"))\n        pl, _ = dataset_to_point_list(ds, sample_dims=["chain", "draw"])\n        assert isinstance(pl, list)\n        assert len(pl) == 6\n        assert isinstance(pl[0], dict)\n        assert isinstance(pl[0]["A"], np.ndarray)\n\n    def test_dataset_to_point_list_str_key(self):\n        # Check that non-str keys are caught\n        ds = xarray.Dataset()\n        ds[3] = xarray.DataArray([1, 2, 3])\n        with pytest.raises(ValueError, match="must be str"):\n            dataset_to_point_list(ds, sample_dims=["chain", "draw"])\n',
        }
